#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007
#define MAXN 100000

int min, max;
int used[MAXN + 1];
int perm[MAXN + 1];

void backtrack(int n, int idx) {
    if (idx == n) {
        // calculate min and max
        int k = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (perm[i] > perm[j]) {
                    k++;
                }
            }
        }
        min = k;
        max = k;
        return;
    }
    for (int i = 1; i <= n; i++) {
        if (!used[i]) {
            used[i] = 1;
            perm[idx] = i;
            backtrack(n, idx + 1);
            used[i] = 0;
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int m = n / 2;
        for (int i = 0; i < m; i++) {
            int idx, val;
            scanf("%d %d", &idx, &val);
            perm[idx - 1] = val;
            used[val] = 1;
        }
        min = MOD;
        max = -1;
        backtrack(n, m);
        printf("%d %d\n", min, max);
    }
    return 0;
}

