    if (idx == n) {
        // calculate min and max
        int k = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (perm[i] > perm[j]) {
                    k++;
                }
            }
        }
        min = k;
        max = k;
        return;
    }
    for (int i = 1; i <= n; i++) {
        if (used.find(i) == used.end()) {
